package cn.mtplayer.tv;
import android.content.Context;import android.graphics.Color;import android.graphics.Typeface;import android.graphics.drawable.GradientDrawable;import android.view.View;import android.view.ViewGroup;import android.widget.Button;import android.widget.EditText;import android.widget.LinearLayout;import android.widget.TextView;
public final class TvUi {public static final int BG=Color.rgb(9,12,16),SURFACE=Color.rgb(21,25,32),HIGH=Color.rgb(32,37,45),RED=Color.rgb(240,25,45),TEXT=Color.rgb(247,248,250),MUTED=Color.rgb(155,163,174);public static int dp(Context c,int v){return Math.round(v*c.getResources().getDisplayMetrics().density);}public static TextView title(Context c,String s,int z){TextView v=new TextView(c);v.setText(s);v.setTextColor(TEXT);v.setTextSize(z);v.setTypeface(Typeface.DEFAULT,Typeface.BOLD);return v;}public static TextView text(Context c,String s){TextView v=new TextView(c);v.setText(s);v.setTextColor(MUTED);v.setTextSize(16);return v;}public static Button button(Context c,String s,boolean primary){Button b=new Button(c);b.setText(s);b.setTextColor(TEXT);b.setTextSize(16);b.setAllCaps(false);b.setFocusable(true);style(b,primary?RED:HIGH,false);b.setOnFocusChangeListener((v,f)->{style(v,primary?RED:HIGH,f);v.animate().scaleX(f?1.04f:1f).scaleY(f?1.04f:1f).translationY(f?-dp(c,3):0).setDuration(120).start();});return b;}public static EditText input(Context c,String h){EditText e=new EditText(c);e.setHint(h);e.setHintTextColor(MUTED);e.setTextColor(TEXT);e.setTextSize(18);e.setSingleLine(true);e.setFocusable(true);e.setPadding(dp(c,18),0,dp(c,18),0);style(e,HIGH,false);e.setOnFocusChangeListener((v,f)->style(v,HIGH,f));return e;}public static LinearLayout column(Context c){LinearLayout l=new LinearLayout(c);l.setOrientation(LinearLayout.VERTICAL);l.setPadding(dp(c,34),dp(c,28),dp(c,34),dp(c,30));l.setBackgroundColor(BG);return l;}public static LinearLayout.LayoutParams matchWrap(){return new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,ViewGroup.LayoutParams.WRAP_CONTENT);}public static void style(View view,int color,boolean focused){GradientDrawable g=new GradientDrawable();g.setColor(color);g.setCornerRadius(dp(view.getContext(),12));g.setStroke(dp(view.getContext(),focused?3:1),focused?RED:Color.rgb(49,56,68));view.setBackground(g);}private TvUi(){}}
